import subprocess

def convertDocument(inputFile, outputFile, format):
    """
    Converts documents between formats using LibreOffice headless mode.

    Args:
        inputFile: Path to the input file.
        outputFile: Path to the output file.
        format: Conversion format.
    """

    # Command to convert document
    command = [
        "libreoffice",
        "--headless",
        "--nologo",
        "--norestore",
        "--convert-to",
        format,
        inputFile,
        outputFile,
    ]

    # Execute LibreOffice command
    subprocess.run(command, check=True)